package docker.org.apache.karaf.docker.command;

@ Command ( scope = "docker" , name = "version" , description = "Show the Docker version information" ) @ Service public class VersionCommand extends DockerCommandSupport { @ Override public Object execute ( ) throws Exception { Version version = getDockerService ( ) . version ( url ) ; System . out . println ( "Version: " + version . getVersion ( ) ) ; System . out . println ( "Os: " + version . getOs ( ) ) ; System . out . println ( "Kernel version: " + version . getKernelVersion ( ) ) ; System . out . println ( "Go version: " + version . getGoVersion ( ) ) ; System . out . println ( "Git commit: " + version . getGitCommit ( ) ) ; System . out . println ( "Arch: " + version . getArch ( ) ) ; System . out . println ( "API version: " + version . getApiVersion ( ) ) ; System . out . println ( "Build time: " + version . getBuildTime ( ) ) ; System . out . println ( "Experimental: " + version . getExperimental ( ) ) ; return null ; } }